'use client'
import { batch, cn, useComputed, useSignal, useSignalEffect, useSignals } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import { Fragment, useId, useRef } from 'react'
import type { KeyboardEvent, ReactNode } from 'react'
import { flushSync } from 'react-dom'
import { Button } from '../button/button'
import { Checkbox } from '../checkbox/checkbox'
import styles from './data-table.module.css'

export interface Column<Row> {
  key: string
  header: string
  sortable?: boolean
  render?: (row: Row) => ReactNode
  align?: 'start' | 'end'
  width?: string
}

export type SortDirection = 'asc' | 'desc'

export interface SortState {
  key: string
  direction: SortDirection
}

export interface DataTableLabels {
  search?: string
  empty?: string
  selectAll?: string
  selectRow?: string
  itemsSelected?: (n: number) => string
  expandRow?: string
  previousPage?: string
  nextPage?: string
}

export interface DataTableProps<Row> {
  columns: Column<Row>[]
  rows: Row[]
  getRowId?: (row: Row) => string
  sort?: SortState
  defaultSort?: SortState
  sortMode?: 'client' | 'server'
  onSortChange?: (sort: SortState | undefined) => void
  searchable?: boolean
  pagination?: { pageSize: number; pageSizeOptions?: number[] }
  selection?: { mode: 'single' | 'multi'; selected?: string[]; onChange?: (ids: string[]) => void }
  batchActions?: { id?: string; label: string; onClick: (selectedIds: string[]) => void }[]
  renderExpandedRow?: (row: Row) => ReactNode
  density?: 'compact' | 'normal' | 'relaxed'
  zebra?: boolean
  stickyHeader?: boolean
  loading?: boolean
  emptyState?: ReactNode
  title?: string
  description?: string
  labels?: DataTableLabels
  className?: string
  virtualized?: boolean
  rowHeight?: number
  windowSize?: number
  overscan?: number
}

interface Entry<Row> {
  row: Row
  id: string
}

function cellValue<Row>(row: Row, key: string): unknown {
  return (row as Record<string, unknown>)[key]
}

function compareValues(a: unknown, b: unknown): number {
  if (typeof a === 'number' && typeof b === 'number') return a - b
  return String(a ?? '').localeCompare(String(b ?? ''))
}

export function DataTable<Row>({
  columns,
  rows,
  getRowId,
  sort,
  defaultSort,
  sortMode = 'client',
  onSortChange,
  searchable = false,
  pagination,
  selection,
  batchActions,
  renderExpandedRow,
  density = 'normal',
  zebra = false,
  stickyHeader = false,
  loading = false,
  emptyState,
  title,
  description,
  labels,
  className,
  virtualized = false,
  rowHeight = 40,
  windowSize = 20,
  overscan = 3,
}: DataTableProps<Row>) {
  useSignals()
  const baseId = useId()
  const resolvedLabels = {
    search: labels?.search ?? t(builtin.dataTable.search),
    empty: labels?.empty ?? t(builtin.dataTable.empty),
    selectAll: labels?.selectAll ?? t(builtin.dataTable.selectAll),
    selectRow: labels?.selectRow ?? t(builtin.dataTable.selectRow),
    itemsSelected: (n: number) =>
      labels?.itemsSelected?.(n) ?? t(builtin.dataTable.itemsSelected, { count: n }),
    expandRow: labels?.expandRow ?? t(builtin.dataTable.expandRow),
    previousPage: labels?.previousPage ?? t(builtin.dataTable.previousPage),
    nextPage: labels?.nextPage ?? t(builtin.dataTable.nextPage),
  }
  const l = resolvedLabels

  // Sync props into signals during render so computeds see fresh data.
  const rowsSignal = useSignal(rows)
  rowsSignal.value = rows
  const columnsSignal = useSignal(columns)
  columnsSignal.value = columns

  const sortSignal = useSignal<SortState | undefined>(sort ?? defaultSort)
  if (sort !== undefined) sortSignal.value = sort

  const selectedSignal = useSignal<string[]>(selection?.selected ?? [])
  if (selection?.selected !== undefined) selectedSignal.value = selection.selected

  const querySignal = useSignal('')
  const pageSignal = useSignal(1)
  const pageSizeSignal = useSignal(pagination?.pageSize ?? 0)
  const expandedSignal = useSignal<ReadonlySet<string>>(new Set())

  // Virtualization
  const scrollContainerRef = useRef<HTMLDivElement>(null)
  const scrollTop = useSignal(0)

  useSignalEffect(() => {
    if (!virtualized) return
    const el = scrollContainerRef.current
    if (!el) return
    const onScroll = () => {
      flushSync(() => {
        scrollTop.value = el.scrollTop
      })
    }
    el.addEventListener('scroll', onScroll, { passive: true })
    return () => el.removeEventListener('scroll', onScroll)
  })

  const entries = useComputed<Entry<Row>[]>(() =>
    rowsSignal.value.map((row, index) => ({
      row,
      id: getRowId ? getRowId(row) : String(index),
    })),
  )

  const filtered = useComputed<Entry<Row>[]>(() => {
    const query = querySignal.value.trim().toLowerCase()
    if (!query) return entries.value
    const cols = columnsSignal.value
    return entries.value.filter((entry) =>
      cols.some((col) =>
        String(cellValue(entry.row, col.key) ?? '')
          .toLowerCase()
          .includes(query),
      ),
    )
  })

  const sorted = useComputed<Entry<Row>[]>(() => {
    const current = sortSignal.value
    if (!current || sortMode === 'server') return filtered.value
    const indexed = filtered.value.map((entry, index) => [entry, index] as const)
    indexed.sort((a, b) => {
      let result = compareValues(cellValue(a[0].row, current.key), cellValue(b[0].row, current.key))
      if (current.direction === 'desc') result = -result
      return result !== 0 ? result : a[1] - b[1]
    })
    return indexed.map(([entry]) => entry)
  })

  const pageCount = useComputed(() =>
    pagination ? Math.max(1, Math.ceil(filtered.value.length / pageSizeSignal.value)) : 1,
  )
  const currentPage = useComputed(() => Math.min(pageSignal.value, pageCount.value))
  const paged = useComputed<Entry<Row>[]>(() => {
    if (!pagination) return sorted.value
    const start = (currentPage.value - 1) * pageSizeSignal.value
    return sorted.value.slice(start, start + pageSizeSignal.value)
  })

  const visibleStart = useComputed(() =>
    virtualized ? Math.floor(scrollTop.value / rowHeight) : 0,
  )
  const visibleEnd = useComputed(() =>
    virtualized
      ? Math.min(visibleStart.value + windowSize + overscan * 2, paged.value.length)
      : paged.value.length,
  )
  const visibleEntries = useComputed<Entry<Row>[]>(() =>
    virtualized ? paged.value.slice(visibleStart.value, visibleEnd.value) : paged.value,
  )

  const cycleSort = (key: string) => {
    const current = sortSignal.value
    let next: SortState | undefined
    if (!current || current.key !== key) next = { key, direction: 'asc' }
    else if (current.direction === 'asc') next = { key, direction: 'desc' }
    else next = undefined
    batch(() => {
      if (sort === undefined) sortSignal.value = next
      pageSignal.value = 1
    })
    onSortChange?.(next)
  }

  const onTableKeyDown = (e: KeyboardEvent<HTMLTableElement>) => {
    if (!['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'].includes(e.key)) return
    const table = e.currentTarget
    const focusables = Array.from(
      table.querySelectorAll<HTMLElement>('th button, td button, td input[type="checkbox"]'),
    )
    const index = focusables.indexOf(document.activeElement as HTMLElement)
    if (index === -1) return
    e.preventDefault()
    const row = (el: HTMLElement) => el.closest('tr')
    let next: HTMLElement | undefined
    if (e.key === 'ArrowRight' || e.key === 'ArrowLeft') {
      const dir = e.key === 'ArrowRight' ? 1 : -1
      const candidate = focusables[index + dir]
      if (candidate && row(candidate) === row(focusables[index]!)) next = candidate
    } else {
      const dir = e.key === 'ArrowDown' ? 1 : -1
      const current = focusables[index]!
      for (let i = index + dir; i >= 0 && i < focusables.length; i += dir) {
        if (row(focusables[i]!) !== row(current)) {
          next = focusables[i]
          break
        }
      }
    }
    next?.focus()
  }

  const setSelected = (ids: string[]) => {
    if (selection?.selected === undefined) selectedSignal.value = ids
    selection?.onChange?.(ids)
  }

  const toggleRow = (id: string) => {
    const current = selectedSignal.value
    if (selection?.mode === 'single') {
      setSelected(current.includes(id) ? [] : [id])
    } else {
      setSelected(current.includes(id) ? current.filter((x) => x !== id) : [...current, id])
    }
  }

  const toggleExpanded = (id: string) => {
    const next = new Set(expandedSignal.value)
    if (next.has(id)) next.delete(id)
    else next.add(id)
    expandedSignal.value = next
  }

  const pageEntries = paged.value
  const selectedIds = selectedSignal.value
  const expanded = expandedSignal.value
  const allPageSelected =
    pageEntries.length > 0 && pageEntries.every((entry) => selectedIds.includes(entry.id))
  const somePageSelected = pageEntries.some((entry) => selectedIds.includes(entry.id))
  const renderedEntries = visibleEntries.value
  const vStart = visibleStart.value
  const vEnd = visibleEnd.value

  const toggleAll = () => {
    const pageIds = pageEntries.map((entry) => entry.id)
    if (allPageSelected) {
      setSelected(selectedIds.filter((id) => !pageIds.includes(id)))
    } else {
      setSelected([...new Set([...selectedIds, ...pageIds])])
    }
  }

  const colCount = columns.length + (selection ? 1 : 0) + (renderExpandedRow ? 1 : 0)
  // Pad partial pages with a spacer row so the table keeps a constant height —
  // the pagination controls stay put as the user pages through.
  const fillerCount =
    pagination && !virtualized && renderedEntries.length > 0
      ? Math.max(0, pageSizeSignal.value - renderedEntries.length)
      : 0
  const titleId = `${baseId}-title`
  const descriptionId = `${baseId}-description`
  const totalRows = filtered.value.length
  const rangeStart = totalRows === 0 ? 0 : (currentPage.value - 1) * pageSizeSignal.value + 1
  const rangeEnd = totalRows === 0 ? 0 : rangeStart + pageEntries.length - 1
  const showBatchBar = !!batchActions && batchActions.length > 0 && selectedIds.length > 0

  return (
    <div
      className={cn(styles['root'], className)}
      data-density={density}
      data-zebra={zebra || undefined}
      data-sticky-header={stickyHeader || undefined}
      data-paginated={pagination ? true : undefined}
    >
      <span aria-live="polite" className={styles['srOnly']}>
        {selectedSignal.value.length > 0 ? l.itemsSelected(selectedSignal.value.length) : ''}
      </span>
      {(title !== undefined || description !== undefined || searchable) && (
        <div className={styles['toolbar']}>
          {(title !== undefined || description !== undefined) && (
            <div className={styles['heading']}>
              {title !== undefined && (
                <div id={titleId} className={styles['title']}>
                  {title}
                </div>
              )}
              {description !== undefined && (
                <div id={descriptionId} className={styles['description']}>
                  {description}
                </div>
              )}
            </div>
          )}
          {searchable && (
            <input
              type="search"
              className={styles['search']}
              aria-label={l.search}
              placeholder={l.search}
              value={querySignal.value}
              onChange={(event) => {
                querySignal.value = event.target.value
                pageSignal.value = 1
              }}
            />
          )}
        </div>
      )}
      {showBatchBar && (
        <div className={styles['batchBar']}>
          <span className={styles['batchCount']}>{l.itemsSelected(selectedIds.length)}</span>
          <div className={styles['batchActions']}>
            {batchActions.map((action, i) => (
              <Button
                key={action.id ?? `${i}-${action.label}`}
                size="sm"
                variant="secondary"
                onClick={() => action.onClick(selectedIds)}
              >
                {action.label}
              </Button>
            ))}
          </div>
        </div>
      )}
      <div
        ref={virtualized ? scrollContainerRef : undefined}
        className={cn(styles['scroller'], virtualized && styles['scrollerVirtualized'])}
      >
        <table
          className={styles['table']}
          aria-labelledby={title !== undefined ? titleId : undefined}
          aria-describedby={description !== undefined ? descriptionId : undefined}
          aria-busy={loading || undefined}
          aria-rowcount={virtualized ? pageEntries.length : undefined}
          onKeyDown={onTableKeyDown}
        >
          <colgroup>
            {renderExpandedRow && <col className={styles['controlCol']} />}
            {selection && <col className={styles['controlCol']} />}
            {columns.map((col) => (
              <col
                key={col.key}
                style={col.width !== undefined ? { width: col.width } : undefined}
              />
            ))}
          </colgroup>
          <thead>
            <tr>
              {renderExpandedRow && (
                <th scope="col" className={styles['controlCell']}>
                  <span className={styles['srOnly']}>{l.expandRow}</span>
                </th>
              )}
              {selection && (
                <th scope="col" className={styles['controlCell']}>
                  {selection.mode === 'multi' ? (
                    <Checkbox
                      aria-label={l.selectAll}
                      checked={allPageSelected}
                      indeterminate={somePageSelected && !allPageSelected}
                      onChange={toggleAll}
                    />
                  ) : (
                    <span className={styles['srOnly']}>{l.selectRow}</span>
                  )}
                </th>
              )}
              {columns.map((col) => {
                const direction =
                  sortSignal.value?.key === col.key ? sortSignal.value.direction : undefined
                const ariaSort =
                  direction === 'asc' ? 'ascending' : direction === 'desc' ? 'descending' : 'none'
                return (
                  <th
                    key={col.key}
                    scope="col"
                    data-align={col.align ?? 'start'}
                    aria-sort={col.sortable ? ariaSort : undefined}
                  >
                    {col.sortable ? (
                      <button
                        type="button"
                        className={styles['sortButton']}
                        data-state={ariaSort}
                        onClick={() => cycleSort(col.key)}
                      >
                        {col.header}
                      </button>
                    ) : (
                      col.header
                    )}
                  </th>
                )
              })}
            </tr>
          </thead>
          <tbody>
            {loading &&
              Array.from({ length: 5 }, (_, rowIndex) => (
                <tr key={rowIndex} className={styles['row']}>
                  {Array.from({ length: colCount }, (_, cellIndex) => (
                    <td key={cellIndex}>
                      <span className={styles['shimmer']} aria-hidden="true" />
                    </td>
                  ))}
                </tr>
              ))}
            {!loading && pageEntries.length === 0 && (
              <tr data-empty-row>
                <td colSpan={colCount} className={styles['emptyCell']}>
                  {emptyState ?? l.empty}
                </td>
              </tr>
            )}
            {!loading && virtualized && vStart > 0 && (
              <tr aria-hidden="true" style={{ height: vStart * rowHeight }} />
            )}
            {!loading &&
              renderedEntries.map((entry, index) => {
                const absoluteIndex = virtualized ? vStart + index : index
                const isSelected = selectedIds.includes(entry.id)
                const isExpanded = expanded.has(entry.id)
                return (
                  <Fragment key={entry.id}>
                    <tr
                      className={styles['row']}
                      data-parity={absoluteIndex % 2 === 0 ? 'even' : 'odd'}
                      data-state={isSelected ? 'selected' : undefined}
                      aria-rowindex={virtualized ? vStart + index + 1 : undefined}
                    >
                      {renderExpandedRow && (
                        <td className={styles['controlCell']}>
                          <button
                            type="button"
                            className={styles['expandButton']}
                            aria-expanded={isExpanded}
                            aria-label={l.expandRow}
                            data-state={isExpanded ? 'open' : 'closed'}
                            onClick={() => toggleExpanded(entry.id)}
                          >
                            <span className={styles['chevron']} aria-hidden="true" />
                          </button>
                        </td>
                      )}
                      {selection && (
                        <td className={styles['controlCell']}>
                          <Checkbox
                            aria-label={l.selectRow}
                            checked={isSelected}
                            onChange={() => toggleRow(entry.id)}
                          />
                        </td>
                      )}
                      {columns.map((col) => (
                        <td key={col.key} data-align={col.align ?? 'start'}>
                          {col.render
                            ? col.render(entry.row)
                            : String(cellValue(entry.row, col.key) ?? '')}
                        </td>
                      ))}
                    </tr>
                    {renderExpandedRow && (
                      <tr
                        className={styles['expansionRow']}
                        data-state={isExpanded ? 'open' : 'closed'}
                      >
                        <td colSpan={colCount}>
                          <div
                            className={styles['expansionGrid']}
                            data-state={isExpanded ? 'open' : 'closed'}
                          >
                            <div className={styles['expansionInner']}>
                              {renderExpandedRow(entry.row)}
                            </div>
                          </div>
                        </td>
                      </tr>
                    )}
                  </Fragment>
                )
              })}
            {!loading && virtualized && vEnd < pageEntries.length && (
              <tr aria-hidden="true" style={{ height: (pageEntries.length - vEnd) * rowHeight }} />
            )}
            {fillerCount > 0 && (
              <tr aria-hidden="true" data-filler-row>
                <td
                  colSpan={colCount}
                  style={{ blockSize: `calc(var(--_row-height) * ${fillerCount})`, padding: 0 }}
                />
              </tr>
            )}
          </tbody>
        </table>
      </div>
      {pagination && (
        <div className={styles['footer']}>
          {pagination.pageSizeOptions && (
            <label className={styles['pageSize']}>
              <span>Rows per page</span>
              <select
                value={pageSizeSignal.value}
                onChange={(event) => {
                  pageSizeSignal.value = Number(event.target.value)
                  pageSignal.value = 1
                }}
              >
                {pagination.pageSizeOptions.map((option) => (
                  <option key={option} value={option}>
                    {option}
                  </option>
                ))}
              </select>
            </label>
          )}
          <span className={styles['range']}>
            {rangeStart}–{rangeEnd} of {totalRows}
          </span>
          <div className={styles['pageButtons']}>
            <button
              type="button"
              className={styles['pageButton']}
              aria-label={l.previousPage}
              disabled={currentPage.value <= 1}
              onClick={() => {
                pageSignal.value = currentPage.value - 1
              }}
            >
              <span aria-hidden="true">‹</span>
            </button>
            <button
              type="button"
              className={styles['pageButton']}
              aria-label={l.nextPage}
              disabled={currentPage.value >= pageCount.value}
              onClick={() => {
                pageSignal.value = currentPage.value + 1
              }}
            >
              <span aria-hidden="true">›</span>
            </button>
          </div>
        </div>
      )}
    </div>
  )
}

@layer cascivo.component {
  .root {
    --_row-height: 3rem;
    display: flex;
    flex-direction: column;
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-surface);
    background-color: var(--cascivo-color-surface);
    overflow: hidden;
  }

  .root[data-density='compact'] {
    --_row-height: 2.25rem;
  }
  .root[data-density='normal'] {
    --_row-height: 3rem;
  }
  .root[data-density='relaxed'] {
    --_row-height: 3.75rem;
  }

  /* Toolbar */
  .toolbar {
    display: flex;
    align-items: flex-end;
    justify-content: space-between;
    gap: var(--cascivo-space-4);
    padding: var(--cascivo-space-3) var(--cascivo-space-4);
    border-block-end: 1px solid var(--cascivo-color-border);
  }

  .heading {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-1);
  }

  .title {
    font-size: var(--cascivo-text-base);
    font-weight: var(--cascivo-font-semibold);
    color: var(--cascivo-color-text);
  }

  .description {
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text-subtle);
  }

  .search {
    appearance: none;
    height: 2rem;
    min-inline-size: 14rem;
    padding-inline: var(--cascivo-space-3);
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text);
    background-color: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-field);
    outline: none;
    transition:
      border-color var(--cascivo-duration-150) var(--cascivo-ease-out),
      box-shadow var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover:not(:focus) {
      border-color: var(--cascivo-color-border-strong);
    }

    &:focus-visible {
      border-color: var(--cascivo-color-accent);
      box-shadow: 0 0 0 3px color-mix(in srgb, var(--cascivo-color-accent) 20%, transparent);
    }
  }

  /* Batch bar */
  .batchBar {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: var(--cascivo-space-4);
    padding: var(--cascivo-space-2) var(--cascivo-space-4);
    background-color: var(--cascivo-color-bg-subtle);
    border-block-end: 1px solid var(--cascivo-color-border);
  }

  .batchCount {
    font-size: var(--cascivo-text-sm);
    font-weight: var(--cascivo-font-medium);
    color: var(--cascivo-color-text);
  }

  .batchActions {
    display: flex;
    gap: var(--cascivo-space-2);
  }

  /* Table scroller */
  .scroller {
    overflow: auto;
    max-block-size: var(--cascivo-data-table-max-height, none);
  }

  .scrollerVirtualized {
    overflow: auto;
    block-size: var(--cascivo-data-table-height, 400px);
    max-block-size: none;
  }

  .table {
    inline-size: 100%;
    border-collapse: collapse;
    table-layout: auto;
  }

  /* Paginated tables use a fixed layout so column widths stay constant as the
     page changes — content of the visible rows can no longer shift columns. */
  .root[data-paginated='true'] .table {
    table-layout: fixed;
  }

  .table thead th {
    padding-block: var(--cascivo-space-2);
    padding-inline: var(--cascivo-data-table-cell-gap, var(--cascivo-space-4));
    text-align: start;
    font-weight: var(--cascivo-font-semibold);
    font-size: var(--cascivo-text-xs);
    text-transform: uppercase;
    letter-spacing: var(--cascivo-tracking-wide);
    color: var(--cascivo-color-text-subtle);
    background-color: var(--cascivo-color-bg-subtle);
    border-block-end: 1px solid var(--cascivo-color-border);
    white-space: nowrap;
  }

  .table thead th[data-align='end'] {
    text-align: end;
  }

  .table td {
    padding-block: 0;
    padding-inline: var(--cascivo-data-table-cell-gap, var(--cascivo-space-4));
    block-size: var(--_row-height);
    vertical-align: middle;
    border-block-end: 1px solid var(--cascivo-color-border);
    color: var(--cascivo-color-text);
    /* Long unbroken tokens (commit hashes, branch names) wrap inside the cell
       instead of spilling past the padding into the adjacent column — the cause
       of adjacent columns visually touching under table-layout: fixed. */
    overflow-wrap: anywhere;
  }

  .table td[data-align='end'] {
    text-align: end;
  }

  /* Spacer that pads partial pages to a constant height — no divider line. */
  .table tbody tr[data-filler-row] td {
    border-block-end: none;
  }

  /* Sticky header */
  .root[data-sticky-header='true'] .table thead th {
    position: sticky;
    inset-block-start: 0;
    z-index: var(--cascivo-z-raised, 10);
    background-color: var(--cascivo-color-surface);
  }

  /* Zebra striping — of .row keeps expansion rows out of the count */
  .root[data-zebra='true'] .table tbody tr:nth-child(even of .row) {
    background-color: var(--cascivo-color-bg-subtle);
  }

  /* Control columns (expand button / checkbox) */
  .controlCol {
    inline-size: 3rem;
  }

  .controlCell {
    text-align: center;
    padding-inline: var(--cascivo-space-2);
  }

  /* Sort button */
  .sortButton {
    display: inline-flex;
    align-items: center;
    gap: var(--cascivo-space-1);
    background: none;
    border: none;
    padding: 0;
    font-family: inherit;
    font-size: inherit;
    font-weight: inherit;
    text-transform: inherit;
    letter-spacing: inherit;
    color: inherit;
    cursor: pointer;
    outline: none;

    &:focus-visible {
      text-decoration: underline;
    }

    &::after {
      content: '↕';
      font-size: 0.75em;
      opacity: 0.4;
    }

    &[data-state='ascending']::after {
      content: '↑';
      opacity: 0.9;
    }

    &[data-state='descending']::after {
      content: '↓';
      opacity: 0.9;
    }
  }

  /* Row */
  .row {
    content-visibility: auto;
    contain-intrinsic-size: auto var(--_row-height, 3rem);

    &[data-state='selected'] td {
      background-color: color-mix(in srgb, var(--cascivo-color-accent) 8%, transparent);
    }
  }

  /* Empty cell */
  .emptyCell {
    padding: var(--cascivo-space-8) var(--cascivo-space-4);
    text-align: center;
    color: var(--cascivo-color-text-muted);
  }

  /* Expansion row */
  .expansionRow {
    &[data-state='closed'] {
      display: none;
    }
  }

  .expansionGrid {
    overflow: hidden;
  }

  .expansionInner {
    padding: var(--cascivo-space-4);
  }

  /* Expand button */
  .expandButton {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    inline-size: 1.5rem;
    block-size: 1.5rem;
    background: none;
    border: none;
    cursor: pointer;
    color: var(--cascivo-color-text-muted);
    border-radius: var(--cascivo-radius-control);
    outline: none;

    &:focus-visible {
      box-shadow: 0 0 0 2px var(--cascivo-color-accent);
    }

    &:hover {
      color: var(--cascivo-color-text);
      background-color: var(--cascivo-color-bg-subtle);
    }
  }

  .chevron {
    display: block;
    inline-size: 0.75rem;
    block-size: 0.75rem;
    border-inline-end: 2px solid currentColor;
    border-block-end: 2px solid currentColor;
    transform: rotate(45deg);
    transition: transform var(--cascivo-duration-150) var(--cascivo-ease-out);
  }

  .expandButton[data-state='open'] .chevron {
    transform: rotate(-135deg);
  }

  /* Loading shimmer — compositor-safe (translate only) */
  .shimmer {
    display: block;
    block-size: 0.875rem;
    inline-size: 80%;
    position: relative;
    overflow: hidden;
    background-color: var(--cascivo-color-bg-subtle);
    border-radius: var(--cascivo-radius-indicator);

    &::after {
      content: '';
      position: absolute;
      inset: 0;
      translate: -100% 0;
      background: linear-gradient(90deg, transparent, var(--cascivo-color-surface), transparent);
      animation: shimmer var(--cascivo-duration-500, 500ms) var(--cascivo-ease-in-out, ease-in-out)
        infinite;
    }
  }

  @keyframes shimmer {
    to {
      translate: 100% 0;
    }
  }

  /* Footer pagination */
  .footer {
    display: flex;
    align-items: center;
    justify-content: flex-end;
    gap: var(--cascivo-space-4);
    padding: var(--cascivo-space-3) var(--cascivo-space-4);
    border-block-start: 1px solid var(--cascivo-color-border);
    font-size: var(--cascivo-text-sm);
  }

  .pageSize {
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-2);
    color: var(--cascivo-color-text-muted);

    select {
      appearance: none;
      height: 2rem;
      padding-inline: var(--cascivo-space-2);
      font-family: var(--cascivo-font-sans);
      font-size: var(--cascivo-text-sm);
      color: var(--cascivo-color-text);
      background-color: var(--cascivo-color-surface);
      border: 1px solid var(--cascivo-color-border);
      border-radius: var(--cascivo-radius-field);
      cursor: pointer;
      outline: none;

      &:focus-visible {
        border-color: var(--cascivo-color-accent);
        box-shadow: 0 0 0 3px color-mix(in srgb, var(--cascivo-color-accent) 20%, transparent);
      }
    }
  }

  .range {
    color: var(--cascivo-color-text-muted);
    white-space: nowrap;
  }

  .pageButtons {
    display: flex;
    gap: var(--cascivo-space-1);
  }

  .pageButton {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    inline-size: 2rem;
    block-size: 2rem;
    background: none;
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-control);
    cursor: pointer;
    color: var(--cascivo-color-text);
    font-size: var(--cascivo-text-base);
    outline: none;
    transition:
      background-color var(--cascivo-duration-150) var(--cascivo-ease-out),
      border-color var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover:not(:disabled) {
      background-color: var(--cascivo-color-bg-subtle);
      border-color: var(--cascivo-color-border-strong);
    }

    &:focus-visible {
      border-color: var(--cascivo-color-accent);
      box-shadow: 0 0 0 3px color-mix(in srgb, var(--cascivo-color-accent) 20%, transparent);
    }

    &:disabled {
      /* Dim via a muted foreground, not opacity — opacity:0.4 on the glyph
         dropped the disabled arrow below 4.5:1 (WCAG color-contrast). */
      color: var(--cascivo-color-text-muted);
      cursor: not-allowed;
    }
  }

  /* Screen-reader only utility */
  .srOnly {
    position: absolute;
    inline-size: 1px;
    block-size: 1px;
    overflow: hidden;
    clip-path: inset(50%);
    white-space: nowrap;
  }
}
